for i, b in enumerate(books[:10]):
    details = b.get('details')
    if details:
        # Print first 200 characters
        snippet = details[:200]
    else:
        snippet = None
    print(i, 'book_id:', b.get('book_id'), 'details snippet:', snippet)

# Now try extraction on these details

def extract_year_robust(details):
    if not details:
        return None
    # Look for month name + day + year pattern (Jan 1, 2004)
    m = re.search(r'\b(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s*(\d{4})\b', details, re.I)
