import json, re
book_path = locals()['var_functions.query_db:8']
if isinstance(book_path, str) and book_path.endswith('.json'):
    with open(book_path) as f:
        books = json.load(f)
else:
    books = book_path

# Print first 20 books' book_id and a snippet of details
samples = []
for i, b in enumerate(books[:20]):
    details = b.get('details', '')
    snippet = details[:300] if details else ''
    samples.append({'book_id': b.get('book_id'), 'snippet': snippet})
    print(i, b.get('book_id'), 'Snippet:', snippet[:200])
    print('---')

# Test regex on these snippets

def test_regex(text):
    # Try month day, year
    m = re.search(r'\b(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s*(\d{4})\b', text, re.I)
    if m:
        return 'month-day-year', int(m.group(1))
    # Try "published on" phrase
    m = re.search(r'published\s+on\s+(?:[A-Za-z]+\s+)?(?:\d{1,2},\s*)?(\d{4})\b', text, re.I)
    if m:
        return 'published-on', int(m.group(1))
    # Try any 4-digit year
    m = re.search(r'\b(19\d{2}|20\d{2})\b', text)
    if m:
        return 'simple-year', int(m.group(1))
    return None, None

print('Test regex on snippets:')
for s in samples:
    typ, yr = test_regex(s['snippet'])
    print(s['book_id'], typ, yr)

